package com.google.gson.internal;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

class ReflectionAccessFilterHelperTest {

  @Test
  void testCanAccess_returnsTrue() throws Exception {
    AccessibleObject accessibleObject = mock(AccessibleObject.class);
    Object obj = new Object();

    // Mock AccessChecker.INSTANCE.canAccess to return true
    try (MockedStatic<AccessChecker> mockedAccessChecker = Mockito.mockStatic(AccessChecker.class)) {
      mockedAccessChecker.when(() -> AccessChecker.INSTANCE.canAccess(accessibleObject, obj)).thenReturn(true);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObject, obj);
      assertTrue(result);
    }
  }

  @Test
  void testCanAccess_returnsFalse() throws Exception {
    AccessibleObject accessibleObject = mock(AccessibleObject.class);
    Object obj = new Object();

    // Mock AccessChecker.INSTANCE.canAccess to return false
    try (MockedStatic<AccessChecker> mockedAccessChecker = Mockito.mockStatic(AccessChecker.class)) {
      mockedAccessChecker.when(() -> AccessChecker.INSTANCE.canAccess(accessibleObject, obj)).thenReturn(false);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObject, obj);
      assertFalse(result);
    }
  }

  @Test
  void testPrivateConstructor() throws Exception {
    var constructor = ReflectionAccessFilterHelper.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    Object instance = constructor.newInstance();
    assertNotNull(instance);
  }
}
